final:
module RefModule (
        input clk,
        input clear,
        input load,
        input [7:0] data,
        output reg [7:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (clear)
		q <= 8'b00000000;
	else if (load)
		q <= data;
end

endmodule
